        AND VALUE ? 'v'
        AND VALUE ? 'i'
        AND VALUE ? 'c'
        AND VALUE ? 'hm'
        AND VALUE->>'v' = '3'
      );
  END IF;

  COMMENT ON DOMAIN public.bigint_eq IS 'EQL encrypted bigint (equality)';

  --! @brief Encrypted domain public.bigint_ord_ore.
  IF NOT EXISTS (
    SELECT 1 FROM pg_type
